import{_ as r,o as a,c as d,a2 as o}from"./chunks/framework.DZO5kRrk.js";const u=JSON.parse('{"title":"计算器套装矩阵 — 产品规划文档","description":"","frontmatter":{},"headers":[],"relativePath":"harmony-calculator-suite.md","filePath":"harmony-calculator-suite.md"}'),n={name:"harmony-calculator-suite.md"};function e(s,t,l,h,i,g){return a(),d("div",null,[...t[0]||(t[0]=[o(`<h1 id="计算器套装矩阵-—-产品规划文档" tabindex="-1">计算器套装矩阵 — 产品规划文档 <a class="header-anchor" href="#计算器套装矩阵-—-产品规划文档" aria-label="Permalink to &quot;计算器套装矩阵 — 产品规划文档&quot;">​</a></h1><p><strong>版本</strong>: v0.1 <strong>平台</strong>: HarmonyOS NEXT <strong>日期</strong>: 2026-07 <strong>开发顺序</strong>: 与图像矩阵并行，技术无依赖</p><hr><h2 id="为什么做计算器套装" tabindex="-1">为什么做计算器套装 <a class="header-anchor" href="#为什么做计算器套装" aria-label="Permalink to &quot;为什么做计算器套装&quot;">​</a></h2><ul><li><strong>技术极简</strong>：纯数学逻辑，不依赖任何系统 API，ArkTS 实现几乎无坑</li><li><strong>开发最快</strong>：无需真机调试功能逻辑，每个套装 1-2 天可出</li><li><strong>需求刚性</strong>：房贷/工资/健康计算是真实高频需求，用户主动搜索</li><li><strong>内容护城河</strong>：计算公式 + 场景说明做扎实后，竞品难以快速赶上</li><li><strong>零运维</strong>：全离线，数据全本地，上线后不需要任何维护</li></ul><hr><h2 id="app-1-房贷计算套装" tabindex="-1">App 1：房贷计算套装 <a class="header-anchor" href="#app-1-房贷计算套装" aria-label="Permalink to &quot;App 1：房贷计算套装&quot;">​</a></h2><p><strong>目标用户</strong>：购房者、换房者、提前还贷决策者</p><h3 id="功能模块" tabindex="-1">功能模块 <a class="header-anchor" href="#功能模块" aria-label="Permalink to &quot;功能模块&quot;">​</a></h3><table tabindex="0"><thead><tr><th>计算器</th><th>核心输入</th><th>核心输出</th></tr></thead><tbody><tr><td><strong>等额本息计算</strong></td><td>贷款额/年限/利率</td><td>月供/总利息/还款总额/还款明细表</td></tr><tr><td><strong>等额本金计算</strong></td><td>同上</td><td>首月月供/递减规律/总利息对比</td></tr><tr><td><strong>提前还款计算</strong></td><td>已还期数/提前还款额</td><td>缩短年限 vs 减少月供两种方案对比</td></tr><tr><td><strong>公积金计算</strong></td><td>商贷+公积金混合</td><td>月供拆分/总利息/公积金余额消耗</td></tr><tr><td><strong>买房总费用</strong></td><td>房价/首付比例/城市</td><td>首付/税费/中介费/总成本清单</td></tr></tbody></table><p><strong>差异化</strong>：不只给结果，给<strong>决策建议</strong>——&quot;提前还 10 万，选缩短年限省 X 万利息，选减月供省 Y 元/月，建议选…&quot;</p><h3 id="商业模式" tabindex="-1">商业模式 <a class="header-anchor" href="#商业模式" aria-label="Permalink to &quot;商业模式&quot;">​</a></h3><ul><li>免费：等额本息/公积金计算</li><li>订阅解锁：提前还款对比、完整还款明细表导出（PDF/截图）</li></ul><hr><h2 id="app-2-工资薪酬套装" tabindex="-1">App 2：工资薪酬套装 <a class="header-anchor" href="#app-2-工资薪酬套装" aria-label="Permalink to &quot;App 2：工资薪酬套装&quot;">​</a></h2><p><strong>目标用户</strong>：求职者（谈薪）、在职员工（算税）、HR（核算）</p><h3 id="功能模块-1" tabindex="-1">功能模块 <a class="header-anchor" href="#功能模块-1" aria-label="Permalink to &quot;功能模块&quot;">​</a></h3><table tabindex="0"><thead><tr><th>计算器</th><th>说明</th></tr></thead><tbody><tr><td><strong>税前↔税后互算</strong></td><td>输入税前算税后，或输入期望税后反推税前（高频需求）</td></tr><tr><td><strong>个人所得税</strong></td><td>月收入/专项扣除/全年速算，支持 2024 年最新税率表</td></tr><tr><td><strong>社保公积金计算</strong></td><td>按城市选择缴纳比例，算出五险一金明细</td></tr><tr><td><strong>年终奖计算</strong></td><td>年终奖个税单独计税方案 vs 合并计税对比</td></tr><tr><td><strong>时薪/日薪换算</strong></td><td>月薪↔时薪↔日薪，考虑法定工作时长</td></tr><tr><td><strong>涨薪影响计算</strong></td><td>涨薪 X% 后实际到手增加多少</td></tr></tbody></table><p><strong>差异化</strong>：税前税后<strong>双向互算</strong>是大多数竞品没做好的，这是核心差异点。</p><h3 id="商业模式-1" tabindex="-1">商业模式 <a class="header-anchor" href="#商业模式-1" aria-label="Permalink to &quot;商业模式&quot;">​</a></h3><ul><li>免费：税前税后互算、个税计算</li><li>订阅解锁：多城市社保配置、年度税单导出、薪资方案对比</li></ul><hr><h2 id="app-3-健康计算套装" tabindex="-1">App 3：健康计算套装 <a class="header-anchor" href="#app-3-健康计算套装" aria-label="Permalink to &quot;App 3：健康计算套装&quot;">​</a></h2><p><strong>目标用户</strong>：健身/减脂人群、关注健康的中青年</p><h3 id="功能模块-2" tabindex="-1">功能模块 <a class="header-anchor" href="#功能模块-2" aria-label="Permalink to &quot;功能模块&quot;">​</a></h3><table tabindex="0"><thead><tr><th>计算器</th><th>说明</th></tr></thead><tbody><tr><td><strong>BMI 体质指数</strong></td><td>身高体重 → BMI + 体重健康区间</td></tr><tr><td><strong>基础代谢率 (BMR)</strong></td><td>Mifflin-St Jeor 公式，区分男女</td></tr><tr><td><strong>每日热量需求 (TDEE)</strong></td><td>BMR × 活动系数，按目标（减脂/增肌/维持）给出建议摄入</td></tr><tr><td><strong>体脂率估算</strong></td><td>腰围/颈围法 (Navy Method)，区分男女</td></tr><tr><td><strong>减脂周期预估</strong></td><td>目标体重/每日热量缺口 → 预计达标时间</td></tr><tr><td><strong>运动热量消耗</strong></td><td>常见运动类型 × 时长 × 体重 → 消耗卡路里</td></tr></tbody></table><p><strong>差异化</strong>：不只给数字，给<strong>下一步行动建议</strong>——&quot;你的 TDEE 是 2100 大卡，减脂建议摄入 1600 大卡，每天快走 40 分钟消耗约 250 大卡&quot;。</p><h3 id="商业模式-2" tabindex="-1">商业模式 <a class="header-anchor" href="#商业模式-2" aria-label="Permalink to &quot;商业模式&quot;">​</a></h3><ul><li>免费：BMI、BMR、TDEE 基础计算</li><li>订阅解锁：减脂计划制定、历史数据记录、导出报告</li></ul><hr><h2 id="app-4-装修预算套装" tabindex="-1">App 4：装修预算套装 <a class="header-anchor" href="#app-4-装修预算套装" aria-label="Permalink to &quot;App 4：装修预算套装&quot;">​</a></h2><p><strong>目标用户</strong>：装修业主，一线搜索需求明确</p><h3 id="功能模块-3" tabindex="-1">功能模块 <a class="header-anchor" href="#功能模块-3" aria-label="Permalink to &quot;功能模块&quot;">​</a></h3><table tabindex="0"><thead><tr><th>计算器</th><th>说明</th></tr></thead><tbody><tr><td><strong>瓷砖用量</strong></td><td>房间面积/瓷砖规格/损耗率 → 需购买块数+费用</td></tr><tr><td><strong>涂料/墙漆用量</strong></td><td>墙面面积/涂刷遍数/单桶覆盖面积 → 需购桶数</td></tr><tr><td><strong>地板用量</strong></td><td>铺贴面积/地板规格/铺贴方式 → 需购平方米+损耗</td></tr><tr><td><strong>装修预算估算</strong></td><td>按套型面积/装修档次给出材料+人工参考预算</td></tr><tr><td><strong>面积计算</strong></td><td>房间面积/墙面面积/踢脚线长度辅助计算</td></tr></tbody></table><h3 id="商业模式-3" tabindex="-1">商业模式 <a class="header-anchor" href="#商业模式-3" aria-label="Permalink to &quot;商业模式&quot;">​</a></h3><ul><li>免费：瓷砖/地板用量计算</li><li>订阅解锁：完整预算清单导出、多房间汇总</li></ul><hr><h2 id="app-5-日期时间套装" tabindex="-1">App 5：日期时间套装 <a class="header-anchor" href="#app-5-日期时间套装" aria-label="Permalink to &quot;App 5：日期时间套装&quot;">​</a></h2><p><strong>目标用户</strong>：通用，高频刚需</p><h3 id="功能模块-4" tabindex="-1">功能模块 <a class="header-anchor" href="#功能模块-4" aria-label="Permalink to &quot;功能模块&quot;">​</a></h3><table tabindex="0"><thead><tr><th>计算器</th><th>说明</th></tr></thead><tbody><tr><td><strong>工龄/年龄计算</strong></td><td>精确到年月日，支持计算未来日期</td></tr><tr><td><strong>日期差计算</strong></td><td>两个日期相差几天/周/月/年</td></tr><tr><td><strong>倒计时</strong></td><td>距某个日期还有多少天（考试/结婚/生日）</td></tr><tr><td><strong>工作日计算</strong></td><td>两个日期间工作日天数（排除法定节假日）</td></tr><tr><td><strong>农历转换</strong></td><td>公历↔农历互转</td></tr></tbody></table><hr><h2 id="开发路线图" tabindex="-1">开发路线图 <a class="header-anchor" href="#开发路线图" aria-label="Permalink to &quot;开发路线图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Week 1    房贷计算套装（最高搜索量，优先）</span></span>
<span class="line"><span>Week 2    工资薪酬套装（税前税后互算差异点强）</span></span>
<span class="line"><span>Week 3    健康计算套装</span></span>
<span class="line"><span>Week 4    日期时间套装（技术最简，最快出）</span></span>
<span class="line"><span>Week 5    装修预算套装</span></span></code></pre></div><hr><h2 id="整体商业预期" tabindex="-1">整体商业预期 <a class="header-anchor" href="#整体商业预期" aria-label="Permalink to &quot;整体商业预期&quot;">​</a></h2><table tabindex="0"><thead><tr><th>App</th><th>核心搜索词</th><th>月均预期收入</th></tr></thead><tbody><tr><td>房贷计算套装</td><td>&quot;房贷计算器&quot; &quot;提前还款&quot;</td><td>500-1500 元</td></tr><tr><td>工资薪酬套装</td><td>&quot;税前税后计算&quot; &quot;工资计算器&quot;</td><td>500-1500 元</td></tr><tr><td>健康计算套装</td><td>&quot;BMI计算&quot; &quot;TDEE计算&quot;</td><td>300-800 元</td></tr><tr><td>装修预算套装</td><td>&quot;瓷砖用量计算&quot; &quot;装修预算&quot;</td><td>200-600 元</td></tr><tr><td>日期时间套装</td><td>&quot;工作日计算&quot; &quot;倒计时&quot;</td><td>200-500 元</td></tr><tr><td><strong>合计</strong></td><td>—</td><td><strong>1700-4900 元/月</strong></td></tr></tbody></table>`,47)])])}const b=r(n,[["render",e]]);export{u as __pageData,b as default};
